const MAX_LENGTH = 3800;
const text = $('Format Response').item.json.formatted_response;
const chatId = $('Format Response').item.json.chat_id;
const userId = $('Format Response').item.json.user_id;
const timestamp = $('Format Response').item.json.timestamp;

const chunks = [];
let currentChunk = '';

// Split by lines to avoid breaking in the middle of content
const lines = text.split('\n');

for (const line of lines) {
  // If adding this line would exceed the limit, save current chunk and start new one
  if (currentChunk.length + line.length + 1 > MAX_LENGTH && currentChunk.length > 0) {
    chunks.push(currentChunk);
    currentChunk = line;
  } else {
    currentChunk += (currentChunk ? '\n' : '') + line;
  }
}

// Add the last chunk
if (currentChunk) {
  chunks.push(currentChunk);
}

// Return array of items, one per chunk
return chunks.map((chunk, index) => ({
  json: {
    message_text: chunk,
    chat_id: chatId,
    user_id: userId,
    timestamp: timestamp,
    part: index + 1,
    total_parts: chunks.length
  }
}));

