const reviewOutput = $input.item.json.output;
let score = 0;
let comment = "";

if (typeof reviewOutput === "string") {
  try {
    const parsed = JSON.parse(reviewOutput);
    score = parsed.score;
    comment = parsed.comment;
  } catch(e) {
    score = 0;
    comment = "Ошибка парсинга оценки";
  }
} else if (typeof reviewOutput === "object" && reviewOutput !== null) {
  score = reviewOutput.score || 0;
  comment = reviewOutput.comment || "Нет комментария";
}

return {
  json: {
    score: score,
    comment: comment,
    original_plan: JSON.stringify($('Suggest Visualizations').item.json.output)
  }
};
